import { describe, it, expect, vi, beforeEach } from 'vitest';

vi.mock('../src/utils/spawn', () => ({
    spawnPM: vi.fn().mockResolvedValue({ exitCode: 0, stdout: '', stderr: '' }),
}));

vi.mock('../src/detect', () => ({
    detectPackageManager: vi.fn(),
}));

vi.mock('../src/utils/output', () => ({
    isJsonMode: vi.fn().mockReturnValue(false),
    printJSON: vi.fn(),
    printHuman: vi.fn(),
}));

import { run } from '../src/commands/run';
import { spawnPM } from '../src/utils/spawn';
import { detectPackageManager } from '../src/detect';

describe('run', () => {
    beforeEach(() => { vi.clearAllMocks(); });

    it('should generate npm run <script>', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'npm', version: '10.0.0', reason: 'default' });
        await run('dev', [], {});
        expect(spawnPM).toHaveBeenCalledWith('npm', ['run', 'dev'], expect.anything());
    });

    it('should generate yarn <script> (no "run" prefix)', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'yarn', version: '1.22.0', reason: 'lockfile', lockfile: 'yarn.lock' });
        await run('dev', [], {});
        expect(spawnPM).toHaveBeenCalledWith('yarn', ['dev'], expect.anything());
    });

    it('should generate pnpm <script>', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'pnpm', version: '8.0.0', reason: 'default' });
        await run('dev', [], {});
        expect(spawnPM).toHaveBeenCalledWith('pnpm', ['dev'], expect.anything());
    });

    it('should generate bun run <script>', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'bun', version: '1.0.0', reason: 'default' });
        await run('dev', [], {});
        expect(spawnPM).toHaveBeenCalledWith('bun', ['run', 'dev'], expect.anything());
    });

    it('should error when no script specified', async () => {
        const result = await run('', [], {});
        expect(result.exitCode).toBe(1);
        expect(spawnPM).not.toHaveBeenCalled();
    });
});
